import{_ as e,o as p,c as t,j as r,a as b,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"这辈子有了","description":"","frontmatter":{},"headers":[],"relativePath":"7.UA/2.训练及血统/这辈子有了.md","filePath":"7.UA/2.训练及血统/这辈子有了.md"}'),n={name:"7.UA/2.训练及血统/这辈子有了.md"};function o(d,a,_,l,i,c){return p(),t("div",null,[...a[0]||(a[0]=[r("h1",{id:"这辈子有了",tabindex:"-1"},[b("这辈子有了 "),r("a",{class:"header-anchor",href:"#这辈子有了","aria-label":'Permalink to "这辈子有了"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),s('<h1 id="这辈子有了-1" tabindex="-1">这辈子有了 <a class="header-anchor" href="#这辈子有了-1" aria-label="Permalink to &quot;这辈子有了&quot;">​</a></h1><p>D级：夏令营兵王<br> D+600<br> 一周夏令营，一生军旅情，你在小学参加过军训夏令营，在那里锻炼出了强健的精神</p><p>【眼睛瞪得像铜铃】<br> 在夏令营训练后，你变得非常精神，无论什么情况都挺直腰板瞪大眼睛，<br> 直到瞪得眼花，连鬼都觉得尴尬，这使得你获得【灵感视觉】【黑暗视觉】</p><p>【时刻准备着】<br> 经过艰苦的训练后，你养成了时刻警戒的意识。<br> 现在即使你睡着了，只要有人动了你手上的武器，你就会立即醒过来瞪着对方看。<br> 怎么做到的？——实际上你根本不睡，你获得【无需休息】效果</p><p>【复制体父子兵】<br> 夏令营的训练让你获得了强大的模仿学习能力，正好你的长辈喜欢拍某音小视频，所以你拍了和他一起走正步的小视频，动作完全一致仿佛克隆人<br> 当你的敏感范围内存在同样购买了此训练的友方时，<br> 每轮一次，当你执行一项该友方已经执行过的检定时，你获得1点技艺加值。</p><p>C级：白袜体育生<br> C+1200<br> 上了初中，虽然你智力不行，但是你身体很结实，成为了体育生</p><p>【初中必吃榜】<br> 因为你健康的肉体，精神的外表，稚嫩的心灵，你深受许多人的关爱<br> 见到你的NPC对你的好感度提升一级，至多到友善，特别的，这一效果必须要你穿着白色袜子并展示出来才能生效（白色丝袜也行）</p><p>【我一怒之下】<br> 曾经你不小心被核弹烫伤，还好你是体育生，沉淀一下就好，但是这股钻心的痛你至今无法忘记<br> 你免疫【剧痛】点数带来的减值以及严重状态，同时你获得快速医疗2（24点医疗点）.</p><p>B级：精神小鬼火<br> B+2400<br> 九年义务教育后，你没能成功攻克中考，最终选择进厂深造</p><p>【进厂打螺丝】<br> 工厂里的流水线作业练就了你精湛的技术，你的【器用】技能检定获得等同于你【内在最高支线等级数】（即b3a4s5）的附加成功<br> 如果你在攻击螺丝类生物（比如田螺，海螺，加坦杰厄等），则你的检定再获得等量的熟练加值</p><p>【鬼火摩托车】<br> 你对载具选择有着独特的品味，每场影片幕间，你都可以免费选择自己的一台载具进行免费涂装，这仅会带来画风上的效果<br> 你熟练地掌握了用载具发出噪音和光污染的技巧<br> 你以【智力+器用：载具操作+辅助专业：精密操作（手艺）】检定进行的载具攻击附带等量的【耳鸣】和【目眩】点数</p><p>【摇花手】<br> 你爱上了一种独特的艺术形式，通过有规律的扭动肢体来展现你放荡不羁的个性<br> 以一个标准动作，针对一个你触及范围内的目标，你大喊一声“等一下，XXX（对方的名字）！”，然后开始摇花手，这会使对方产生极度的困惑和不解<br> 你以【敏捷+运动：摇花手】进行检定，该次检定获得4点增强加值，对方以意志豁免对抗你的出目，若你胜出，对方会一直痴迷于看你摇花手并不进行任何行动，直到受到伤害<br> 这是一个B级影响心灵来源的【思维控制】效果，你必须每轮以标准动作维持摇花手，否则对方会脱离此状态</p><p>特别的，你可以在获得此训练时选定一种你已有的【技能+武器专业】检定代替【运动+摇花手】进行检定<br> 表现为你拿着你的武器摇花手，选定后不可更改</p><p>A级：碧桂园保安<br> A+4800<br> 人到中年，体力大不如前，你不得不退厂，选择在碧桂园小区成为一名保安。</p><p>【拦截外卖】<br> 虽然你知道保安保护不了任何人，但你可以拦截业主的外卖<br> 购买后，选定一项你已有的攻击检定方式，选定后不可更改</p><p>以一个标准动作，你进行全力防御，并且直到你的下一轮开始，你对触及范围内的友方提供【全遮蔽】、【超级坚韧】、【强拦截】效果<br> 每轮一次，当你选定的攻击方式的射程内，有敌方目标攻击你或你触及范围内的友方，你可以立即以选定的攻击方式对该敌方目标进行一次不带任何技艺的攻击，这次攻击获得2点增强加值。<br> 此次攻击若命中，则你会从对方身上夺得一份【“国朝来袭”牌TMD时尚外卖】，对方则会因为外卖被抢而受到与你此次攻击出目相同的【沮丧】不良点数，标准豁免</p><p>【“国朝来袭”牌TMD时尚外卖】：<br> 由纯科技炸鸡、纯科技土豆丝、纯科技米饭组成的盖浇饭，加上便宜小糖水，塑料软体勺组成的豪华套餐<br> 拿到后你顷刻炼化，获得持续一轮的【快速医疗7：84医疗点数】和【异常点医疗3：72医疗点数】</p><p>【爷们要战斗】特别的，当你的性别是女性时，此特性改名为【娘们要战斗】<br> 特别特别的，当你的性别既不是男性又不是女性时，此特性改名为【自由公民们要战斗】<br> 即使一把年纪了你也热爱拍短视频到发到网上，而曾经你发的摇花手的视频已经火爆了网络，你决定好好利用这份流量来鼓舞年轻人现在你进行【敏捷+运动：摇花手】的射程范围提升至以你为圆心的240米圆形，并且当你摇花手时，可以同时唱着此特性的名称（例如，当你是男性时，应唱“爷们要战斗~爷们要战斗~”）</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',20)])])}const m=e(n,[["render",o]]);export{f as __pageData,m as default};
